  function buildMap(lang) {
    const m = {};
    for (const r of ROWS) {
      m[r.es] = r[lang];
    }
    return m;
  }

  const EDITOR_LANGS = ["en", "de", "fr", "it", "nl", "pt", "ru", "el", "zh", "ro"];
  const MAP = { es: {} };
  for (const L of EDITOR_LANGS) {
    MAP[L] = buildMap(L);
  }
  for (const r of ROWS) {
    MAP.es[r.es] = r.es;
  }

  function foldEditorUiKey(s) {
    try {
      return String(s || "")
        .normalize("NFD")
        .replace(/\p{M}/gu, "")
        .trim()
        .toLowerCase();
    } catch (_e) {
      return String(s || "")
        .toLowerCase()
        .trim();
    }
  }

  const editorUiFoldToCanonicalEs = new Map();
  for (const r of ROWS) {
    const canon = r.es;
    if (typeof canon !== "string" || !canon) {
      continue;
    }
    const f = foldEditorUiKey(canon);
    if (!editorUiFoldToCanonicalEs.has(f)) {
      editorUiFoldToCanonicalEs.set(f, canon);
    }
  }

  window.NodaliaI18n.editorUiMaps = MAP;
